","/src/app/App.tsx":"import domtoimage from "dom-to-image-more";
import { jsPDF } from "jspdf";
import { useState } from "react";
import { Download, FileDown, Image as ImageIcon } from "lucide-react";
import { DownloadableHomepage } from "./components/DownloadableHomepage";

export default function App() {
  const [showDownloadMenu, setShowDownloadMenu] = useState(false);
  const [isDownloading, setIsDownloading] = useState(false);

  /**
   * Capture the target element as a PNG data-URL using dom-to-image-more.
   *
   * Why dom-to-image-more instead of html2canvas:
   *   html2canvas ships its own CSS parser that chokes on oklch() color
   *   functions used by Tailwind v4. dom-to-image-more serialises the DOM
   *   into an SVG foreignObject and lets the *browser* handle all style
   *   resolution — so oklch is never parsed by user-land JavaScript.
   */
  const captureDataUrl = async (): Promise<string> => {
    const element = document.getElementById("downloadable-content");
    if (!element) throw new Error("Target element #downloadable-content not found");

    const scale = 2;
    const width = element.scrollWidth;
    const height = element.scrollHeight;

    return domtoimage.toPng(element, {
      width: width * scale,
      height: height * scale,
      style: {
        transform: `scale(${scale})`,
        transformOrigin: "top left",
        width: `${width}px`,
        height: `${height}px`,
      },
      // Allow cross-origin images (Unsplash etc.)
      useCORS: true,
      // Fallback placeholder for any image that fails to load
      imagePlaceholder:
        "data:image/gif;base64,R0lGODlhAQABAIAAAAAAAP///yH5BAEAAAAALAAAAAABAAEAAAIBRAA7",
    });
  };

  const downloadAsImage = async () => {
    setIsDownloading(true);
    try {
      const dataUrl = await captureDataUrl();
      const link = document.createElement("a");
      link.download = "truebase-homepage-design.png";
      link.href = dataUrl;
      link.click();
    } catch (error) {
      console.error("Download failed:", error);
      alert("下载失败，请重试：" + (error as Error).message);
    } finally {
      setIsDownloading(false);
      setShowDownloadMenu(false);
    }
  };

  const downloadAsPDF = async () => {
    setIsDownloading(true);
    try {
      const dataUrl = await captureDataUrl();

      // Build a temporary image to read natural dimensions
      const img = await new Promise<HTMLImageElement>((resolve, reject) => {
        const i = new Image();
        i.onload = () => resolve(i);
        i.onerror = reject;
        i.src = dataUrl;
      });

      const pageW = 210; // A4 width in mm
      const pageH = 297; // A4 height in mm
      const imgH = (img.naturalHeight * pageW) / img.naturalWidth;

      const pdf = new jsPDF({ orientation: "portrait", unit: "mm", format: "a4" });
      let remaining = imgH;
      let yOffset = 0;

      while (remaining > 0) {
        if (yOffset > 0) pdf.addPage();
        pdf.addImage(dataUrl, "PNG", 0, -yOffset, pageW, imgH);
        yOffset += pageH;
        remaining -= pageH;
      }

      pdf.save("truebase-homepage-design.pdf");
    } catch (error) {
      console.error("Download failed:", error);
      alert("下载失败，请重试：" + (error as Error).message);
    } finally {
      setIsDownloading(false);
      setShowDownloadMenu(false);
    }
  };

  return (
    <div className="size-full overflow-y-auto bg-white relative">
      <DownloadableHomepage />

      {/* Floating Download Button */}
      <div className="fixed bottom-8 right-8 z-50">
        {showDownloadMenu && (
          <div className="absolute bottom-full right-0 mb-2 bg-white rounded-lg shadow-lg border border-gray-200 overflow-hidden min-w-[160px]">
            <button
              onClick={downloadAsImage}
              disabled={isDownloading}
              className="flex items-center gap-3 px-6 py-3 hover:bg-gray-50 transition-colors w-full text-left disabled:opacity-50"
            >
              <ImageIcon className="w-5 h-5 text-gray-700" />
              <span className="text-sm font-medium text-gray-900">下载为 PNG</span>
            </button>
            <button
              onClick={downloadAsPDF}
              disabled={isDownloading}
              className="flex items-center gap-3 px-6 py-3 hover:bg-gray-50 transition-colors w-full text-left border-t border-gray-100 disabled:opacity-50"
            >
              <FileDown className="w-5 h-5 text-gray-700" />
              <span className="text-sm font-medium text-gray-900">下载为 PDF</span>
            </button>
          </div>
        )}
        <button
          onClick={() => setShowDownloadMenu(!showDownloadMenu)}
          disabled={isDownloading}
          className="w-14 h-14 bg-[#C8A97E] rounded-full shadow-lg flex items-center justify-center hover:bg-[#B89A6E] transition-colors disabled:opacity-50"
          title="下载设计"
        >
          {isDownloading ? (
            <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin" />
          ) : (
            <Download className="w-6 h-6 text-white" />
          )}
        </button>
      </div>
    </div>
  );
}
